parameters.content:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across all channels.
 * Supports per-channel settings: email, SMS, and webhook.
 * Each channel can be independently enabled/disabled with per-category control.
 */

import type { NotificationType } from './notification.js';

/**
 * Email delivery frequency.
 * - 'immediate': Send emails as events occur.
 * - 'daily_digest': Batch into a daily summary (future implementation).
 * - 'weekly_digest': Batch into a weekly summary (future implementation).
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Per-category subscription settings shared across all channels.
 * Each notification type can be independently enabled or disabled.
 */
export interface CategoryPreferences {
  order_confirmation: boolean;
  order_status_update: boolean;
  welcome: boolean;
  account_updated: boolean;
}

/**
 * @deprecated Use CategoryPreferences instead. Kept for backward compatibility.
 */
export type EmailCategoryPreferences = CategoryPreferences;

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  categories: CategoryPreferences;
}

/**
 * SMS-specific notification preferences.
 */
export interface SmsPreferences {
  enabled: boolean;
  categories: CategoryPreferences;
}

/**
 * Webhook-specific notification preferences.
 */
export interface WebhookPreferences {
  enabled: boolean;
  categories: CategoryPreferences;
}

/**
 * Full user notification preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Partial email preferences for create/update inputs.
 */
export interface EmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  categories?: Partial<CategoryPreferences>;
}

/**
 * Partial SMS preferences for create/update inputs.
 */
export interface SmsPreferencesInput {
  enabled?: boolean;
  categories?: Partial<CategoryPreferences>;
}

/**
 * Partial webhook preferences for create/update inputs.
 */
export interface WebhookPreferencesInput {
  enabled?: boolean;
  categories?: Partial<CategoryPreferences>;
}

/**
 * Input for creating user preferences.
 * All fields are optional — defaults are applied by the service.
 */
export interface CreatePreferencesInput {
  userId: string;
  email?: EmailPreferencesInput;
  sms?: SmsPreferencesInput;
  webhook?: WebhookPreferencesInput;
}

/**
 * Input for updating user preferences.
 */
export interface UpdatePreferencesInput {
  email?: EmailPreferencesInput;
  sms?: SmsPreferencesInput;
  webhook?: WebhookPreferencesInput;
}

/**
 * Returns default category preferences — all notifications enabled.
 */
export function defaultCategoryPreferences(): CategoryPreferences {
  return {
    order_confirmation: true,
    order_status_update: true,
    welcome: true,
    account_updated: true,
  };
}

/**
 * Returns default email preferences — all notifications enabled, immediate delivery.
 */
export function defaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categories: defaultCategoryPreferences(),
  };
}

/**
 * Returns default SMS preferences — all notifications enabled.
 */
export function defaultSmsPreferences(): SmsPreferences {
  return {
    enabled: true,
    categories: defaultCategoryPreferences(),
  };
}

/**
 * Returns default webhook preferences — all notifications enabled.
 */
export function defaultWebhookPreferences(): WebhookPreferences {
  return {
    enabled: true,
    categories: defaultCategoryPreferences(),
  };
}

/**
 * Check if a specific notification type is enabled in email preferences.
 */
export function isEmailCategoryEnabled(
  prefs: EmailPreferences,
  type: NotificationType,
): boolean {
  if (!prefs.enabled) return false;
  return prefs.categories[type] ?? true;
}

/**
 * Check if a specific notification type is enabled for a channel's preferences.
 * Works with any channel preferences that have an enabled flag and categories.
 */
export function isChannelCategoryEnabled(
  prefs: { enabled: boolean; categories: CategoryPreferences },
  type: NotificationType,
): boolean {
  if (!prefs.enabled) return false;
  return prefs.categories[type] ?? true;
}

