parameters.content:
/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for preferences and per-channel shouldSend checks
 * that the NotificationService uses before dispatching notifications.
 * Supports email, SMS, and webhook channels.
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreatePreferencesInput,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import {
  defaultEmailPreferences,
  defaultSmsPreferences,
  defaultWebhookPreferences,
  defaultCategoryPreferences,
  isChannelCategoryEnabled,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if none are set.
   */
  getByUserId(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Create preferences for a user.
   * Merges provided input with defaults so all fields are populated.
   */
  create(input: CreatePreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const emailDefaults = defaultEmailPreferences();
    const emailInput = input.email ?? {};
    const emailCategoriesInput = emailInput.categories ?? {};

    const smsDefaults = defaultSmsPreferences();
    const smsInput = input.sms ?? {};
    const smsCategoriesInput = smsInput.categories ?? {};

    const webhookDefaults = defaultWebhookPreferences();
    const webhookInput = input.webhook ?? {};
    const webhookCategoriesInput = webhookInput.categories ?? {};

    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      email: {
        enabled: emailInput.enabled ?? emailDefaults.enabled,
        frequency: emailInput.frequency ?? emailDefaults.frequency,
        categories: {
          order_confirmation: emailCategoriesInput.order_confirmation ?? emailDefaults.categories.order_confirmation,
          order_status_update: emailCategoriesInput.order_status_update ?? emailDefaults.categories.order_status_update,
          welcome: emailCategoriesInput.welcome ?? emailDefaults.categories.welcome,
          account_updated: emailCategoriesInput.account_updated ?? emailDefaults.categories.account_updated,
        },
      },
      sms: {
        enabled: smsInput.enabled ?? smsDefaults.enabled,
        categories: {
          order_confirmation: smsCategoriesInput.order_confirmation ?? smsDefaults.categories.order_confirmation,
          order_status_update: smsCategoriesInput.order_status_update ?? smsDefaults.categories.order_status_update,
          welcome: smsCategoriesInput.welcome ?? smsDefaults.categories.welcome,
          account_updated: smsCategoriesInput.account_updated ?? smsDefaults.categories.account_updated,
        },
      },
      webhook: {
        enabled: webhookInput.enabled ?? webhookDefaults.enabled,
        categories: {
          order_confirmation: webhookCategoriesInput.order_confirmation ?? webhookDefaults.categories.order_confirmation,
          order_status_update: webhookCategoriesInput.order_status_update ?? webhookDefaults.categories.order_status_update,
          welcome: webhookCategoriesInput.welcome ?? webhookDefaults.categories.welcome,
          account_updated: webhookCategoriesInput.account_updated ?? webhookDefaults.categories.account_updated,
        },
      },
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    this.logger.info(`Created preferences for user: ${input.userId}`);
    return this.repository.save(prefs);
  }

  /**
   * Update existing preferences for a user.
   * Merges updates into the current preferences.
   */
  update(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user: ${userId}`);
    }

    const emailInput = input.email ?? {};
    const emailCategoriesInput = emailInput.categories ?? {};

    const smsInput = input.sms ?? {};
    const smsCategoriesInput = smsInput.categories ?? {};

    const webhookInput = input.webhook ?? {};
    const webhookCategoriesInput = webhookInput.categories ?? {};

    const updated: UserPreferences = {
      ...existing,
      email: {
        enabled: emailInput.enabled ?? existing.email.enabled,
        frequency: emailInput.frequency ?? existing.email.frequency,
        categories: {
          order_confirmation: emailCategoriesInput.order_confirmation ?? existing.email.categories.order_confirmation,
          order_status_update: emailCategoriesInput.order_status_update ?? existing.email.categories.order_status_update,
          welcome: emailCategoriesInput.welcome ?? existing.email.categories.welcome,
          account_updated: emailCategoriesInput.account_updated ?? existing.email.categories.account_updated,
        },
      },
      sms: {
        enabled: smsInput.enabled ?? existing.sms.enabled,
        categories: {
          order_confirmation: smsCategoriesInput.order_confirmation ?? existing.sms.categories.order_confirmation,
          order_status_update: smsCategoriesInput.order_status_update ?? existing.sms.categories.order_status_update,
          welcome: smsCategoriesInput.welcome ?? existing.sms.categories.welcome,
          account_updated: smsCategoriesInput.account_updated ?? existing.sms.categories.account_updated,
        },
      },
      webhook: {
        enabled: webhookInput.enabled ?? existing.webhook.enabled,
        categories: {
          order_confirmation: webhookCategoriesInput.order_confirmation ?? existing.webhook.categories.order_confirmation,
          order_status_update: webhookCategoriesInput.order_status_update ?? existing.webhook.categories.order_status_update,
          welcome: webhookCategoriesInput.welcome ?? existing.webhook.categories.welcome,
          account_updated: webhookCategoriesInput.account_updated ?? existing.webhook.categories.account_updated,
        },
      },
      updatedAt: new Date(),
    };

    this.logger.info(`Updated preferences for user: ${userId}`);
    return this.repository.update(existing.id, updated);
  }

  /**
   * Delete preferences for a user (resets to defaults).
   */
  delete(userId: string): boolean {
    const existing = this.repository.findByUserId(userId);
    if (!existing) return false;
    this.logger.info(`Deleted preferences for user: ${userId}`);
    return this.repository.delete(existing.id);
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Returns true if:
   * - No preferences are set (default: all enabled)
   * - Email is enabled AND the specific category is enabled
   */
  shouldSendEmail(userId: string, type: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);
    if (!prefs) return true; // No preferences = default to all enabled
    return isChannelCategoryEnabled(prefs.email, type);
  }

  /**
   * Check whether a notification should be sent to a user via SMS.
   */
  shouldSendSms(userId: string, type: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);
    if (!prefs) return true;
    return isChannelCategoryEnabled(prefs.sms, type);
  }

  /**
   * Check whether a notification should be sent to a user via webhook.
   */
  shouldSendWebhook(userId: string, type: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);
    if (!prefs) return true;
    return isChannelCategoryEnabled(prefs.webhook, type);
  }

  /**
   * Check whether a notification should be sent via a specific channel.
   * Generic method that dispatches to the appropriate channel check.
   */
  shouldSendChannel(userId: string, type: NotificationType, channel: NotificationChannel): boolean {
    switch (channel) {
      case 'email':
        return this.shouldSendEmail(userId, type);
      case 'sms':
        return this.shouldSendSms(userId, type);
      case 'webhook':
        return this.shouldSendWebhook(userId, type);
      case 'in_app':
        return true; // In-app notifications are always sent
      default:
        return true; // Unknown channels default to sending
    }
  }
}

