});

describe('NotificationService with multi-channel preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailNotificationAdapter;
  let smsAdapter: SmsNotificationAdapter;
  let webhookAdapter: WebhookNotificationAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    const repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    notificationService.setPreferencesService(preferencesService);

    emailAdapter = new EmailNotificationAdapter();
    smsAdapter = new SmsNotificationAdapter();
    webhookAdapter = new WebhookNotificationAdapter({ url: 'https://hooks.example.com/notify' });

    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should send to all channels when no preferences are set', async () => {
    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(3);
    const channels = notifications.map((n) => n.channel).sort();
    expect(channels).toEqual(['email', 'sms', 'webhook']);
  });

  it('should suppress only email when email is disabled', async () => {
    preferencesService.create({
      userId: 'user-1',
      email: { enabled: false },
    });

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(2);
    const channels = notifications.map((n) => n.channel).sort();
    expect(channels).toEqual(['sms', 'webhook']);
  });

  it('should suppress only SMS when SMS is disabled', async () => {
    preferencesService.create({
      userId: 'user-1',
      sms: { enabled: false },
    });

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(2);
    const channels = notifications.map((n) => n.channel).sort();
    expect(channels).toEqual(['email', 'webhook']);
  });

  it('should suppress all channels when all are disabled', async () => {
    preferencesService.create({
      userId: 'user-1',
      email: { enabled: false },
      sms: { enabled: false },
      webhook: { enabled: false },
    });

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress per-category per-channel independently', async () => {
    preferencesService.create({
      userId: 'user-1',
      email: { categories: { welcome: false } },
      sms: { categories: { welcome: true } },
      webhook: { categories: { welcome: false } },
    });

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.channel).toBe('sms');
  });

  it('should send to all channels for category enabled everywhere', async () => {
    preferencesService.create({
      userId: 'user-1',
      email: { categories: { welcome: false, order_confirmation: true } },
      sms: { categories: { welcome: false, order_confirmation: true } },
      webhook: { categories: { welcome: false, order_confirmation: true } },
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(3);
  });
});

